function move(direction){

  if(direction === "up"){
    window.dispatchEvent(new KeyboardEvent("keydown",{key:"ArrowUp",bubbles:true}));
  }

  if(direction === "down"){
    window.dispatchEvent(new KeyboardEvent("keydown",{key:"ArrowDown",bubbles:true}));
  }

  if(direction === "left"){
    window.dispatchEvent(new KeyboardEvent("keydown",{key:"ArrowLeft",bubbles:true}));
  }

  if(direction === "right"){
    window.dispatchEvent(new KeyboardEvent("keydown",{key:"ArrowRight",bubbles:true}));
  }

}

let startX = 0;
let startY = 0;

document.addEventListener("touchstart", (e) => {
  startX = e.touches[0].clientX;
  startY = e.touches[0].clientY;
});

document.addEventListener("touchend", (e) => {

  let endX = e.changedTouches[0].clientX;
  let endY = e.changedTouches[0].clientY;

  let dx = endX - startX;
  let dy = endY - startY;

  if(Math.abs(dx) > Math.abs(dy)){
    if(dx > 0){
      move("right");
    }else{
      move("left");
    }
  }else{
    if(dy > 0){
      move("down");
    }else{
      move("up");
    }
  }

});

document.getElementById("btn-left").addEventListener("touchstart",()=>move("left"));
document.getElementById("btn-up").addEventListener("touchstart",()=>move("up"));
document.getElementById("btn-down").addEventListener("touchstart",()=>move("down"));
document.getElementById("btn-right").addEventListener("touchstart",()=>move("right"));
